const urlString = $.input.searchUrls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.length > 0 && (u.startsWith('http://') || u.startsWith('https://')));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapeListings.response.iterations || [];
let compiled = '';
let successCount = 0;

iterations.forEach((iter, i) => {
  const url = urls[i] || '';
  const data = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;
  compiled += '=== PAGE ' + (i + 1) + ' ===\n';
  compiled += 'URL: ' + url + '\n';
  if (data && data.markdown) {
    compiled += data.markdown.slice(0, 4000) + '\n';
    successCount++;
  } else {
    compiled += 'Failed to scrape\n';
  }
  compiled += '\n';
});

return { compiled: compiled.slice(0, 30000), successCount, totalPages: urls.length };

const d = $.steps.compileListings.output;
const targetRoles = $.input.targetRoles || '';
const goal = $.input.prospectingGoal || 'Identify companies with high hiring intent as potential B2B leads';

let prompt = 'You are a B2B sales intelligence analyst specializing in hiring signal analysis. Extract and analyze job listings from the scraped pages to identify prospecting opportunities.\n\n';
prompt += 'PROSPECTING GOAL: ' + goal + '\n';
if (targetRoles) prompt += 'TARGET ROLES: ' + targetRoles + '\n';
prompt += 'PAGES SCRAPED: ' + d.successCount + ' of ' + d.totalPages + '\n\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract individual job listings with company, title, location, seniority\n';
prompt += '- Identify hiring signals: rapid growth, new departments, leadership changes\n';
prompt += '- Score each company as a prospect (1-10) based on hiring intent\n';
prompt += '- Group companies by hiring intensity and sector\n';
prompt += '- Flag companies matching target roles if specified\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "listings": [\n';
prompt += '    {\n';
prompt += '      "company": "company name",\n';
prompt += '      "title": "job title",\n';
prompt += '      "location": "location",\n';
prompt += '      "seniority": "junior|mid|senior|executive",\n';
prompt += '      "department": "engineering|sales|marketing|ops|other",\n';
prompt += '      "matchesTarget": false\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "companies": [\n';
prompt += '    { "name": "company", "openRoles": 3, "prospectScore": 8, "hiringSignal": "rapid engineering growth", "sector": "SaaS" }\n';
prompt += '  ],\n';
prompt += '  "summary": "overview of hiring landscape",\n';
prompt += '  "topProspects": ["company 1 - reason", "company 2 - reason"],\n';
prompt += '  "trendInsights": ["market trend from hiring data"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { listings: [], companies: [], summary: raw, topProspects: [], trendInsights: [] }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Company', 'Title', 'Location', 'Seniority', 'Department', 'Prospect Score', 'Hiring Signal', 'Matches Target']);

const companyMap = {};
(ai.companies || []).forEach(c => { companyMap[c.name] = c; });

(ai.listings || []).forEach(l => {
  const company = companyMap[l.company] || {};
  rows.push([today, l.company || '', l.title || '', l.location || '', l.seniority || '', l.department || '', String(company.prospectScore || ''), company.hiringSignal || '', l.matchesTarget ? 'YES' : '']);
});
return { rows, listingCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const listings = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Hiring Signal Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Listings Found:* ' + listings.listingCount + ' | *Companies:* ' + (ai.companies || []).length } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.summary.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.topProspects && ai.topProspects.length > 0) {
  let prospectText = '*Top Prospects:*\n';
  ai.topProspects.slice(0, 8).forEach((p, i) => { prospectText += ':dart: ' + (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: prospectText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.trendInsights && ai.trendInsights.length > 0) {
  let trendText = '*Market Trends:*\n';
  ai.trendInsights.forEach((t, i) => { trendText += (i + 1) + '. ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: trendText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallback = 'Hiring Signals: ' + listings.listingCount + ' listings from ' + (ai.companies || []).length + ' companies';
return { blocks, fallback };
